namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

namespace RecipeCommunity.Models;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough, Tomato sauce, Fresh mozzarella, Basil, Olive oil", Steps = "1. Preheat oven to 475°F\n2. Roll out dough\n3. Spread sauce and add cheese\n4. Bake 10-12 minutes\n5. Top with fresh basil", AverageRating = 4.5, RatingCount = 12 },
        new Recipe { Id = 2, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken breast, Yogurt, Tikka spice mix, Tomato puree, Cream, Onion, Garlic, Ginger", Steps = "1. Marinate chicken in yogurt and spices\n2. Grill chicken until charred\n3. Sauté onions, garlic, ginger\n4. Add tomato puree and cream\n5. Add chicken and simmer 15 minutes", AverageRating = 4.8, RatingCount = 20 },
        new Recipe { Id = 3, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef, Taco shells, Lettuce, Tomato, Cheese, Sour cream, Taco seasoning", Steps = "1. Brown ground beef\n2. Add taco seasoning\n3. Warm taco shells\n4. Assemble with toppings", AverageRating = 4.2, RatingCount = 8 },
        new Recipe { Id = 4, Title = "Pad Thai", Category = "Asian", Ingredients = "Rice noodles, Shrimp, Egg, Bean sprouts, Peanuts, Lime, Fish sauce, Tamarind paste", Steps = "1. Soak noodles in warm water\n2. Stir-fry shrimp and egg\n3. Add noodles and sauce\n4. Toss with bean sprouts\n5. Garnish with peanuts and lime", AverageRating = 4.6, RatingCount = 15 },
        new Recipe { Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "Dark chocolate, Butter, Eggs, Sugar, Flour", Steps = "1. Melt chocolate and butter\n2. Whisk eggs and sugar\n3. Fold in flour and chocolate mixture\n4. Pour into ramekins\n5. Bake at 425°F for 12 minutes", AverageRating = 4.9, RatingCount = 25 },
        new Recipe { Id = 6, Title = "Caesar Salad", Category = "Salads", Ingredients = "Romaine lettuce, Parmesan, Croutons, Caesar dressing, Lemon, Anchovy", Steps = "1. Wash and chop romaine\n2. Make dressing with anchovy, lemon, garlic\n3. Toss lettuce with dressing\n4. Top with parmesan and croutons", AverageRating = 4.0, RatingCount = 6 },
    };

    private int _nextId = 7;

    public List<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public List<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is null || stars < 1 || stars > 5) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
        recipe.RatingCount++;
        recipe.AverageRating = Math.Round(totalStars / recipe.RatingCount, 1);
    }

    public void AddRecipe(RecipeSubmission submission)
    {
        _recipes.Add(new Recipe
        {
            Id = _nextId++,
            Title = submission.Title,
            Category = submission.Category,
            Ingredients = submission.Ingredients,
            Steps = submission.Steps,
            AverageRating = 0,
            RatingCount = 0
        });
    }
}

