arguments.file_text:
@page "/"

<PageTitle>Recipe Community</PageTitle>

<h1>🍽️ Recipe Community</h1>
<p class="lead">Discover and share delicious recipes from around the world.</p>

<div class="row mt-4">
    @foreach (var category in RecipeService.GetCategories())
    {
        <div class="col-md-4 mb-3">
            <div class="card h-100">
                <div class="card-body text-center">
                    <h4 class="card-title">@GetEmoji(category) @category</h4>
                    <p class="card-text">@RecipeService.GetByCategory(category).Count recipe(s)</p>
                    <a href="/recipes/category/@category" class="btn btn-primary">Browse</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Inject] private RecipeCommunity.Models.RecipeService RecipeService { get; set; } = default!;

    private string GetEmoji(string category) => category switch
    {
        "Italian" => "🍕",
        "Indian" => "🍛",
        "Mexican" => "🌮",
        "Asian" => "🍜",
        "Desserts" => "🍰",
        "Salads" => "🥗",
        _ => "🍴"
    };
}

@page "/recipes/category/{CategoryName}"

<PageTitle>@CategoryName Recipes</PageTitle>

<h2>@CategoryName Recipes</h2>
<a href="/" class="btn btn-outline-secondary btn-sm mb-3">← Back to Categories</a>

@if (Recipes.Any())
{
    <div class="row">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="text-muted">
                            ⭐ @recipe.AverageRating / 5 (@recipe.RatingCount ratings)
                        </p>
                        <a href="/recipes/@recipe.Id" class="btn btn-sm btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}
else
{
    <p>No recipes found in this category.</p>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    [Inject] private RecipeCommunity.Models.RecipeService RecipeService { get; set; } = default!;

    private List<RecipeCommunity.Models.Recipe> Recipes { get; set; } = new();

    protected override void OnParametersSet()
    {
        Recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipes/{Id:int}"

<PageTitle>@(Recipe?.Title ?? "Recipe")</PageTitle>

@if (Recipe is null)
{
    <p>Recipe not found.</p>
}
else
{
    <a href="/recipes/category/@Recipe.Category" class="btn btn-outline-secondary btn-sm mb-3">← Back to @Recipe.Category</a>

    <h2>@Recipe.Title</h2>
    <span class="badge bg-secondary">@Recipe.Category</span>

    <div class="mt-4">
        <h4>Ingredients</h4>
        <ul>
            @foreach (var ingredient in Recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
            {
                <li>@ingredient</li>
            }
        </ul>
    </div>

    <div class="mt-4">
        <h4>Steps</h4>
        @foreach (var step in Recipe.Steps.Split('\n'))
        {
            <p>@step</p>
        }
    </div>

    <div class="mt-4">
        <h4>Rating</h4>
        <p class="text-muted">⭐ @Recipe.AverageRating / 5 (@Recipe.RatingCount ratings)</p>
        <RecipeCommunity.Components.Pages.Recipes.StarRating RecipeId="Recipe.Id" />
    </div>
}

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private RecipeCommunity.Models.RecipeService RecipeService { get; set; } = default!;

    private RecipeCommunity.Models.Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer

<div class="star-rating">
    <span>Rate this recipe: </span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= _hoveredStar ? "highlighted" : "")"
              @onmouseover="() => _hoveredStar = star"
              @onmouseout="() => _hoveredStar = 0"
              @onclick="() => SubmitRating(star)"
              style="cursor:pointer; font-size:1.5rem;">
            @(star <= _hoveredStar ? "★" : "☆")
        </span>
    }
    @if (_submitted)
    {
        <span class="text-success ms-2">✓ Thanks for rating!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Inject] private RecipeCommunity.Models.RecipeService RecipeService { get; set; } = default!;

    private int _hoveredStar;
    private bool _submitted;

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        _submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe</PageTitle>

<h2>Submit a Recipe</h2>
<p>Share your favorite recipe with the community!</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe has been added to the community.
        <a href="/">Back to Home</a>
    </div>
}
else
{
    <EditForm Model="_submission" OnValidSubmit="HandleSubmit" FormName="recipeForm">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label class="form-label">Title</label>
            <InputText @bind-Value="_submission.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
        </div>

        <div class="mb-3">
            <label class="form-label">Category</label>
            <InputSelect @bind-Value="_submission.Category" class="form-select">
                <option value="">-- Select Category --</option>
                @foreach (var cat in RecipeService.GetCategories())
                {
                    <option value="@cat">@cat</option>
                }
            </InputSelect>
        </div>

        <div class="mb-3">
            <label class="form-label">Ingredients (comma-separated)</label>
            <InputTextArea @bind-Value="_submission.Ingredients" class="form-control" rows="3"
                placeholder="e.g., Flour, Sugar, Butter, Apples" />
        </div>

        <div class="mb-3">
            <label class="form-label">Steps (one per line)</label>
            <InputTextArea @bind-Value="_submission.Steps" class="form-control" rows="5"
                placeholder="1. Preheat oven to 350°F&#10;2. Mix dry ingredients..." />
        </div>

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    [Inject] private RecipeCommunity.Models.RecipeService RecipeService { get; set; } = default!;

    private RecipeCommunity.Models.RecipeSubmission _submission = new();
    private bool _submitted;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(_submission.Title)) return;
        RecipeService.AddRecipe(_submission);
        _submitted = true;
    }
}

@page "/"

<PageTitle>Recipe Community</PageTitle>

<h1>🍽️ Recipe Community</h1>
<p class="lead">Discover and share delicious recipes from around the world.</p>

<div class="row mt-4">
    @foreach (var category in RecipeService.GetCategories())
    {
        <div class="col-md-4 mb-3">
            <div class="card h-100">
                <div class="card-body text-center">
                    <h4 class="card-title">@GetEmoji(category) @category</h4>
                    <p class="card-text">@RecipeService.GetByCategory(category).Count recipe(s)</p>
                    <a href="/recipes/category/@category" class="btn btn-primary">Browse</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Inject] private RecipeCommunity.Models.RecipeService RecipeService { get; set; } = default!;

    private string GetEmoji(string category) => category switch
    {
        "Italian" => "🍕",
        "Indian" => "🍛",
        "Mexican" => "🌮",
        "Asian" => "🍜",
        "Desserts" => "🍰",
        "Salads" => "🥗",
        _ => "🍴"
    };
}

@page "/recipes/category/{CategoryName}"

<PageTitle>@CategoryName Recipes</PageTitle>

<h2>@CategoryName Recipes</h2>
<a href="/" class="btn btn-outline-secondary btn-sm mb-3">← Back to Categories</a>

@if (Recipes.Any())
{
    <div class="row">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="text-muted">
                            ⭐ @recipe.AverageRating / 5 (@recipe.RatingCount ratings)
                        </p>
                        <a href="/recipes/@recipe.Id" class="btn btn-sm btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}
else
{
    <p>No recipes found in this category.</p>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    [Inject] private RecipeCommunity.Models.RecipeService RecipeService { get; set; } = default!;

    private List<RecipeCommunity.Models.Recipe> Recipes { get; set; } = new();

    protected override void OnParametersSet()
    {
        Recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipes/{Id:int}"

<PageTitle>@(Recipe?.Title ?? "Recipe")</PageTitle>

@if (Recipe is null)
{
    <p>Recipe not found.</p>
}
else
{
    <a href="/recipes/category/@Recipe.Category" class="btn btn-outline-secondary btn-sm mb-3">← Back to @Recipe.Category</a>

    <h2>@Recipe.Title</h2>
    <span class="badge bg-secondary">@Recipe.Category</span>

    <div class="mt-4">
        <h4>Ingredients</h4>
        <ul>
            @foreach (var ingredient in Recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
            {
                <li>@ingredient</li>
            }
        </ul>
    </div>

    <div class="mt-4">
        <h4>Steps</h4>
        @foreach (var step in Recipe.Steps.Split('\n'))
        {
            <p>@step</p>
        }
    </div>

    <div class="mt-4">
        <h4>Rating</h4>
        <p class="text-muted">⭐ @Recipe.AverageRating / 5 (@Recipe.RatingCount ratings)</p>
        <RecipeCommunity.Components.Pages.Recipes.StarRating RecipeId="Recipe.Id" />
    </div>
}

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private RecipeCommunity.Models.RecipeService RecipeService { get; set; } = default!;

    private RecipeCommunity.Models.Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer

<div class="star-rating">
    <span>Rate this recipe: </span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= _hoveredStar ? "highlighted" : "")"
              @onmouseover="() => _hoveredStar = star"
              @onmouseout="() => _hoveredStar = 0"
              @onclick="() => SubmitRating(star)"
              style="cursor:pointer; font-size:1.5rem;">
            @(star <= _hoveredStar ? "★" : "☆")
        </span>
    }
    @if (_submitted)
    {
        <span class="text-success ms-2">✓ Thanks for rating!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Inject] private RecipeCommunity.Models.RecipeService RecipeService { get; set; } = default!;

    private int _hoveredStar;
    private bool _submitted;

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        _submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe</PageTitle>

<h2>Submit a Recipe</h2>
<p>Share your favorite recipe with the community!</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe has been added to the community.
        <a href="/">Back to Home</a>
    </div>
}
else
{
    <EditForm Model="_submission" OnValidSubmit="HandleSubmit" FormName="recipeForm">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label class="form-label">Title</label>
            <InputText @bind-Value="_submission.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
        </div>

        <div class="mb-3">
            <label class="form-label">Category</label>
            <InputSelect @bind-Value="_submission.Category" class="form-select">
                <option value="">-- Select Category --</option>
                @foreach (var cat in RecipeService.GetCategories())
                {
                    <option value="@cat">@cat</option>
                }
            </InputSelect>
        </div>

        <div class="mb-3">
            <label class="form-label">Ingredients (comma-separated)</label>
            <InputTextArea @bind-Value="_submission.Ingredients" class="form-control" rows="3"
                placeholder="e.g., Flour, Sugar, Butter, Apples" />
        </div>

        <div class="mb-3">
            <label class="form-label">Steps (one per line)</label>
            <InputTextArea @bind-Value="_submission.Steps" class="form-control" rows="5"
                placeholder="1. Preheat oven to 350°F&#10;2. Mix dry ingredients..." />
        </div>

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    [Inject] private RecipeCommunity.Models.RecipeService RecipeService { get; set; } = default!;

    private RecipeCommunity.Models.RecipeSubmission _submission = new();
    private bool _submitted;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(_submission.Title)) return;
        RecipeService.AddRecipe(_submission);
        _submitted = true;
    }
}

