                placeholder="e.g., Flour, Sugar, Butter, Apples" />
        </div>

        <div class="mb-3">
            <label class="form-label">Steps (one per line)</label>
            <InputTextArea @bind-Value="_submission.Steps" class="form-control" rows="5"
                placeholder="1. Preheat oven to 350°F&#10;2. Mix dry ingredients..." />
        </div>

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    [Inject] private RecipeCommunity.Models.RecipeService RecipeService { get; set; } = default!;

    private RecipeCommunity.Models.RecipeSubmission _submission = new();
    private bool _submitted;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(_submission.Title)) return;
        RecipeService.AddRecipe(_submission);
        _submitted = true;
    }
}

