﻿@page "/"

<PageTitle>Recipe Community</PageTitle>

<h1>🍽️ Recipe Community</h1>
<p class="lead">Discover and share delicious recipes from around the world.</p>

<div class="row mt-4">
    @foreach (var category in RecipeService.GetCategories())
    {
        <div class="col-md-4 mb-3">
            <div class="card h-100">
                <div class="card-body text-center">
                    <h4 class="card-title">@GetEmoji(category) @category</h4>
                    <p class="card-text">@RecipeService.GetByCategory(category).Count recipe(s)</p>
                    <a href="/recipes/category/@category" class="btn btn-primary">Browse</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Inject] private RecipeCommunity.Models.RecipeService RecipeService { get; set; } = default!;

    private string GetEmoji(string category) => category switch
    {
        "Italian" => "🍕",
        "Indian" => "🍛",
        "Mexican" => "🌮",
        "Asian" => "🍜",
        "Desserts" => "🍰",
        "Salads" => "🥗",
        _ => "🍴"
    };
}

